unsafe_example:
// UNSAFE: redirect URL taken directly from query parameter
app.get('/redirect', (req, res) => {
  const target = req.query.url;
  res.redirect(target);
});
// Attacker crafts: https://trusted-app.com/redirect?url=https://evil-phishing.com/login

safe_example:
// SAFE: validate redirect target is a relative path or trusted domain
const TRUSTED_DOMAINS = ['trusted-app.com', 'app.trusted-partner.com'];

app.get('/redirect', (req, res) => {
  const target = req.query.url || '/';

  // Option 1: allow only relative paths
  if (target.startsWith('/') && !target.startsWith('//')) {
    return res.redirect(target);
  }

  // Option 2: validate against domain allowlist
  try {
    const parsed = new URL(target);
    if (TRUSTED_DOMAINS.includes(parsed.hostname)) {
      return res.redirect(target);
    }
  } catch (e) {
    // invalid URL, fall through to default
  }

  res.redirect('/');
});
